('Огненный элементаль', 'Large', 'elemental', 'neutral', 5, 1800, 13, NULL, 102, '12d10+36', '{"walk":50}', '{"str":10,"dex":17,"con":16,"int":6,"wis":10,"cha":7}', '{}', '{}', '["bludgeoning","piercing","slashing"]', '["fire","poison"]', '["exhaustion","grappled","paralyzed","petrified","poisoned","prone","restrained","unconscious"]', '{"darkvision":60}', '[]', '[{"name":"Огненная форма","description":"Существо, касающееся элементаля или ударившее его рукопашной атакой в 5 фт., получает 5 (1d10) огненного урона. Элементаль может проходить сквозь пространство существ и зажигать незащищённые горючие предметы."},{"name":"Свечение","description":"Элементаль излучает яркий свет на 30 фт. и тусклый на 30 фт. дальше."},{"name":"Водная восприимчивость","description":"Каждый галлон воды, выплеснутый на элементаля, наносит ему 1 холодный урон."}]', '[{"name":"Мультиатака","description":"Элементаль совершает две атаки касанием."},{"name":"Касание","description":"Рукопашная атака: +6 к попаданию, досягаемость 5 фт. Урон: 10 (2d6+3) огненного. При попадании цель начинает гореть. Горящая цель получает 5 (1d10) огненного урона в начале каждого хода."}]', '[]', '[]', '[]', false),

('Воздушный элементаль', 'Large', 'elemental', 'neutral', 5, 1800, 15, NULL, 90, '12d10+24', '{"walk":0,"fly":90,"hover":true}', '{"str":14,"dex":20,"con":14,"int":6,"wis":10,"cha":6}', '{}', '{}', '["bludgeoning","piercing","slashing"]', '["lightning","thunder","poison"]', '["exhaustion","grappled","paralyzed","petrified","poisoned","prone","restrained","unconscious"]', '{"darkvision":60}', '[]', '[{"name":"Воздушная форма","description":"Элементаль может проходить сквозь пространство других существ. Другое существо, заканчивающее ход в пространстве элементаля, получает 5 (1d10) урона."}]', '[{"name":"Мультиатака","description":"Элементаль совершает две атаки хлыстом."},{"name":"Хлыст","description":"Рукопашная атака: +8 к попаданию, досягаемость 5 фт. Урон: 14 (2d8+5) дроблящего."},{"name":"Вихрь","description":"Каждое существо в пространстве 5х30 фт. линии должно пройти спасбросок Силы СЛ 13 или получить 3d8+5 дроблящего урона и быть отброшенным."}]', '[]', '[]', '[]', false),

('Вампир', 'Medium', 'undead', 'lawful evil', 13, 10000, 16, 'natural armor', 144, '17d8+68', '{"walk":30,"climb":30}', '{"str":18,"dex":18,"con":18,"int":17,"wis":15,"cha":18}', '{"dex":9,"wis":7,"cha":9}', '{"perception":7,"stealth":9}', '["bludgeoning","piercing","slashing"]', '["necrotic","poison"]', '["charmed"]', '{"darkvision":120}', '["Все, что знал при жизни"]', '[{"name":"Регенерация","description":"Вампир восстанавливает 20 HP в начале хода, если имеет хотя бы 1 HP. Если получил урон сиянием или проточной водой — не работает."},{"name":"Паучье лазание","description":"Вампир может лазать по сложным поверхностям, включая потолок, без проверки."},{"name":"Уязвимости вампира","description":"Вампир погибает если получает урон сиянием или если сломан деревянный кол в его сердце."}]', '[{"name":"Мультиатака","description":"Вампир совершает две атаки — одну безоружным ударом и одну укусом или двумя безоружными ударами."},{"name":"Безоружный удар","description":"Рукопашная атака: +9 к попаданию, досягаемость 5 фт. Урон: 8 (1d8+4) дроблящего. Вместо урона — захват (вырваться СЛ 18)."},{"name":"Укус","description":"Рукопашная атака: +9 к попаданию, досягаемость 5 фт., одно существо (или захваченное). Урон: 7 (1d6+4) колющего + 10 (3d6) некротического. Максимум HP цели уменьшается на эту величину."}]', '[]', '[]', '[{"name":"Легендарное сопротивление","description":"3/день. Если вампир провалил спасбросок, он может выбрать успех."}]', false),

